import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import '../../../header.css'; // Import the CSS module
import logo from '../../assets/logo.png'; // Make sure this path is correct

const Header = () => {
  return (
    <header className="header">
      <div className="container">
        <nav className="navbar">
          {/* Logo */}
          <a href="/" className="logo">
            <img src={logo} alt="Channel4Me Logo" />
          </a>

          {/* Navigation Menu */}
          <ul className="navMenu">
            <li><a href="/" className="navLink active">Home</a></li>
            <li><a href="/features" className="navLink">Features</a></li>
            <li><a href="/doctors" className="navLink">Doctors</a></li>
            <li><a href="/specialties" className="navLink">Specialties</a></li>
            <li><a href="/about" className="navLink">About</a></li>
          </ul>

          {/* Auth Buttons */}
          <div className="navButtons">
            <a href="/login" className="btn btnOutline">
              Log In
            </a>
            <a href="/register" className="btn btnPrimary">
              Sign Up Free
            </a>
          </div>
        </nav>
      </div>
    </header>
  );
};

export default Header;
